DELETE FROM TBL_NOTI_MST
WHERE NOTI_SEQ = #{noti_seq}
AND   FILE_GB    = #{file_gb}

mapper.update:

UPDATE TBL_URL_MST
  SET END_DT   = REPLACE(#{end_dt},'-','') , 
      USE_YN   = #{use_yn}, 
      BIGO     = #{bigo}, 
      UPD_DTTM = NOW(), 
      UPD_USER = #{upd_user}, 
      UPD_IP   = #{upd_ip}
WHERE HOSP_UUID  = #{hosp_uuid} 
  AND START_DT   = REPLACE(#{start_dt},'-','') 
  AND URL_PATH   = #{url_path}
